-- Enrichment marathon batch: PhotoStructure, phpBB, phpIPAM, phpList, Pi-hole, PictShare, PieFed, Pika

-- ── PhotoStructure ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$PhotoStructure is a self-hosted digital asset manager that organizes, deduplicates, and lets you browse your own photo and video library through a private web interface, without uploading files to a third-party cloud.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (Plus plan from $5/month)$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE($q$Small, founder-led team (not publicly disclosed)$q$, company_size),
  headquarters = COALESCE($q$Not publicly disclosed$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$PhotoStructure Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$PhotoStructure review: self-hosted photo and video manager with deduplication, face tagging and no cloud lock-in. See pricing, features and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$PhotoStructure is a self-hosted digital asset manager (DAM) built by founder and CEO Matthew McEachen, who started the project in 2016 as a private alternative to cloud photo services like Google Photos and Apple Photos. It runs as a local application (with Docker support) that scans a user's existing photo and video folders, builds a searchable library with thumbnails and metadata, performs automatic video transcoding, and applies advanced de-duplication so the same image imported from multiple devices or backups is not stored twice. Because the library format is portable and cross-platform, PhotoStructure explicitly promises it will never hold a user's library hostage to a subscription: the free Lite tier can always open and browse an existing library. The paid Plus tier, which costs 5 dollars per month or 42 dollars per year, unlocks advanced de-duplication, richer metadata handling, a more modern mobile-friendly interface, automatic organization, and face tag extraction, plus email support and a 15-day free trial with no credit card required. PhotoStructure also offers income-based discounts for users outside the US, free access for nonprofit and charity workers, and discount coupons for open-source contributors, reflecting its self-description as an entirely subscriber-supported business with no ads or data sharing. Its core differentiators versus alternatives are privacy (all processing and storage stay on hardware the user controls), a single perpetual local library format instead of a proprietary cloud database, and a lightweight installation aimed at photographers, families, and privacy-conscious hobbyists who have large personal archives spread across old hard drives, NAS devices, and phone backups. Target users are individuals and households who want Google Photos-style browsing and organization without surrendering their images to a corporate cloud. Its most direct competitors in the self-hosted photo management space are PhotoPrism, Immich, and Piwigo, all of which similarly index local photo libraries; PhotoStructure differentiates itself with a stronger emphasis on format-portability and its no-lock-in free tier, whereas some competitors lean more heavily on open-source community development models.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '738c4ff8-6bc1-45af-9978-423b14aba862';

