-- ── phpBB ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$phpBB is a free, open-source internet forum and bulletin board software package written in PHP, first released in 2000 and now one of the most widely used forum platforms in the world.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2000, founded_year),
  company_size = COALESCE($q$Not publicly disclosed (largely volunteer-maintained open-source project)$q$, company_size),
  headquarters = COALESCE($q$Marlow, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$, $q$French$q$, $q$Spanish$q$, $q$Italian$q$, $q$Dutch$q$, $q$Portuguese$q$, $q$Russian$q$, $q$Polish$q$, $q$Japanese$q$]::text[],
  seo_title = COALESCE($q$phpBB Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$phpBB review: the free, open-source forum software powering thousands of communities. See features, self-hosting requirements, pros, cons and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$phpBB is a free, open-source internet forum and bulletin board software package written in PHP, originally created by James Atkinson on June 17, 2000, as a simple UBB-like forum for his personal website. Nathan Codding and John Abela joined the project after its source code was moved to SourceForge, and phpBB 1.0.0 was released in December 2000. The software was rewritten from scratch for the phpBB 2.0 line, released in 2002, and again for phpBB3 (codenamed Olympus), which launched in December 2007 and modernized the codebase with a template engine and modular authentication. The project is stewarded by phpBB Limited, a company headquartered in Marlow, United Kingdom, that holds the phpBB trademark; day-to-day development is driven largely by a volunteer community of contributors and translators, with the software localized into more than 50 languages. phpBB is distributed under the GNU General Public License and is free to download, self-host, and modify, requiring only a PHP-capable web server and a supported database such as MySQL, PostgreSQL, or SQLite. Its key differentiators are longevity and ecosystem depth: phpBB has one of the largest libraries of community-built styles, modifications (MODs), and extensions of any open-source forum platform, along with mature moderation tools, permission systems, private messaging, and a built-in search engine. It targets webmasters, hobbyist community builders, gaming clans, support communities, and organizations that want full control over their forum's data and hosting rather than using a hosted SaaS community platform. Because it is self-hosted and free, phpBB's only direct costs are web hosting and optional paid extensions or themes from third-party developers. Its main competitors are Discourse, a more modern JavaScript-based forum platform aimed at real-time discussion; SMF (Simple Machines Forum), another long-running open-source PHP forum system; MyBB, a lighter-weight open-source alternative; and Vanilla Forums, which offers both open-source and hosted commercial options. Compared to these, phpBB is often chosen for its maturity, stability, and the sheer size of its existing user base and plugin ecosystem, though newer platforms like Discourse are frequently preferred for modern, mobile-first discussion experiences.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '4c103625-d77b-4769-a06c-01a9300cd28b';

