-- ── phpIPAM ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$phpIPAM is a free, open-source IP address management (IPAM) web application that helps network administrators track IPv4 and IPv6 subnets, VLANs, and address usage through a PHP and MySQL-based interface.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE($q$Volunteer-maintained open-source project (no formal company)$q$, company_size),
  headquarters = COALESCE($q$Not publicly disclosed$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$phpIPAM Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$phpIPAM review: free open-source IP address management with IPv4/IPv6, VLAN tracking, and a REST API. See features, setup requirements and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$phpIPAM is a free, open-source IP address management (IPAM) application built with PHP, jQuery, and a MySQL database backend, designed to give network administrators a lightweight, self-hosted way to organize, track, and document IP address usage across enterprise, data center, and cloud environments. The project is community-driven and maintained primarily through its GitHub repository, without formal venture backing or a commercial parent company; its core maintainer community operates the project as volunteers, and the software is distributed under the GPL open-source license at no cost. Key features include full IPv4 and IPv6 subnet management, VLAN and VRF tracking across multiple sections and groups, visual subnet maps with automatic free-space indicators, built-in subnet scanning to detect live hosts, a fully-featured REST API for automation and integration with tools like Ansible and Terraform, DNS integration with PowerDNS, NAT documentation, and authentication via Active Directory, LDAP, and RADIUS. Because it has no official paid tier, phpIPAM is typically deployed on a Linux server (Ubuntu, CentOS, Debian) with Apache or nginx, PHP, and MySQL or MariaDB, and is also distributed via Docker images for containerized deployment. Its differentiators relative to commercial IPAM platforms are cost (completely free) and simplicity: it focuses specifically on IP address and subnet documentation rather than being a full network configuration management or monitoring suite. Target users are network engineers, sysadmins, and IT teams at small-to-midsize organizations, service providers, and homelab or self-hosting enthusiasts who need structured IP address tracking without paying for enterprise IPAM licensing. Competing products include NetBox, an open-source DCIM and IPAM tool with broader data-center modeling features; SolarWinds IP Address Manager, a commercial enterprise IPAM product; Infoblox, a large commercial DDI (DNS, DHCP, IPAM) vendor used in large enterprises; and GestioIP, another open-source IPAM alternative. phpIPAM is generally favored over these when a team wants a straightforward, free, self-hosted address tracker with a clean web UI and solid API access, while NetBox and Infoblox are chosen when broader infrastructure modeling or vendor support and SLAs are required.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '42a75ad3-068c-492e-a658-dfdeda416a65';

