-- ── phpList ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$phpList is an open-source email newsletter and marketing platform that organizations can self-host for free or run through phpList's hosted service, used to send campaigns, manage subscriber lists, and automate drip sequences.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted) or from $1/month (hosted service)$q$, starting_price),
  founded_year = COALESCE(2000, founded_year),
  company_size = COALESCE($q$Small company (phpList Ltd, UK-registered)$q$, company_size),
  headquarters = COALESCE($q$United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$, $q$French$q$, $q$Spanish$q$, $q$Dutch$q$, $q$Portuguese$q$, $q$Italian$q$]::text[],
  seo_title = COALESCE($q$phpList Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$phpList review: open-source email newsletter software you can self-host free or run hosted from $1/month. Compare features, pricing and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$phpList is open-source email newsletter and marketing software originally created by Michiel Dethmers, who began developing it in 2000 and led the project for 15 years before handing management to Sam Tuke, who became CEO of phpList Ltd in 2015. The company, phpList Limited, is registered and headquartered in the United Kingdom. phpList's core software is free to download and self-host under an open-source license, requiring the user to supply their own web hosting and a working mail delivery setup; alternatively, phpList offers a hosted service through phplist.com with plans starting around 1 dollar per month, billed either per subscriber or per message, scaling up to sending a million messages a month from around 8 dollars per month. The platform's feature set covers campaign creation and scheduling, subscriber list management with custom fields, autoresponders and drip campaigns, click and open tracking, bounce management, and integrations via API and plugins. phpList differentiates itself from mainstream email marketing SaaS tools primarily through its open-source, self-hostable core, which appeals to organizations that want full control over subscriber data, need to avoid per-contact SaaS pricing at very large list sizes, or operate in regions or sectors (such as nonprofits, NGOs, and public health campaigns) where data sovereignty and cost matter. The company states that roughly 75,000 organizations across 35 countries use phpList. Target users span nonprofits, community organizations, publishers, and developers who want programmatic control over email sending infrastructure, as well as businesses that prefer the predictable low cost of self-hosting over per-subscriber SaaS billing. Its main competitors in the email marketing space include Mailchimp, a much larger hosted SaaS platform with broader marketing automation features; Sendinblue (Brevo), which combines email and SMS marketing; Listmonk, a newer open-source self-hosted newsletter tool; and Mautic, an open-source marketing automation platform with email campaign features. Compared to these, phpList is generally positioned as a lower-cost, more technically-oriented option for teams comfortable managing their own mail infrastructure or willing to pay modest hosted fees rather than per-contact SaaS pricing.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '05c5746c-f3a3-47a9-b647-2b4ab14ad200';

