-- ── PictShare ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$PictShare is a free, open-source, self-hosted image, video, and text hosting service with a simple URL-based resizing and upload API, built by Haschek Solutions.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE($q$Small (Haschek Solutions, Austria)$q$, company_size),
  headquarters = COALESCE($q$Austria$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$PictShare Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$PictShare review: free, open-source self-hosted image and video hosting with a simple resizing API. See features, setup and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$PictShare is a free, open-source, self-hosted image, video, and pastebin-style text hosting service built by Christian Haschek's company Haschek Solutions, based in Austria. It is distributed on GitHub under the Apache-2.0 license and is designed as a lightweight CDN-style service that anyone can deploy on their own server rather than relying on third-party image hosts. PictShare is built in PHP and is entirely file-based, requiring no database, which makes it simple to deploy, back up, and scale. Its core feature is a URL-based API: uploaded images and videos can be resized, filtered, and format-converted simply by editing parameters in the URL, without needing a separate API call or dashboard interaction. On upload, PictShare automatically strips EXIF metadata, including GPS location tags and camera model information, from images, which protects users from unintentionally leaking sensitive data when sharing photos taken on a phone. The tool also supports converting GIFs to MP4 for more efficient playback, converting JPG and PNG images to WebP, deduplicating identical uploads so they do not consume additional storage, and hosting plain text snippets in a pastebin-like fashion. Because it has no company behind it charging for licenses, PictShare has no formal pricing plans; it is entirely free to self-host, and the only cost is the server infrastructure required to run it. Its target users are developers, bloggers, self-hosting enthusiasts, and privacy-conscious individuals who want to host their own images and short videos rather than uploading them to commercial platforms like Imgur or Cloudinary, particularly when EXIF metadata stripping and full data control are priorities. Competing self-hosted alternatives include Chevereto, a popular self-hosted image gallery and hosting script with both free and paid commercial licenses; Lychee, an open-source self-hosted photo-sharing tool; and Linx-server, another lightweight open-source file and image hosting tool. Compared to these, PictShare differentiates itself with its database-free, file-based architecture and its URL-parameter-driven resizing and filtering API, which makes it especially popular for developers who want to embed a simple self-hosted image CDN into their own applications without standing up a separate database.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '9d7aacfb-24f7-4b69-a710-ff2942eeaaa7';

