-- ── PieFed ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$PieFed is a free, open-source, federated link-aggregation and discussion platform built on ActivityPub, offering a Reddit-like community experience that interoperates with Lemmy, Mbin, and the wider Fediverse.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE($q$Small open-source project (primarily one lead developer plus contributors)$q$, company_size),
  headquarters = COALESCE($q$Not publicly disclosed$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$PieFed Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$PieFed review: the free, open-source, federated Reddit-style platform built on ActivityPub. See features, how it compares to Lemmy, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$PieFed is a free, open-source, federated link-aggregation and discussion platform that functions as a Reddit-style alternative built on the ActivityPub protocol, the same federation standard used by Mastodon. It was created by a developer known as Rimu (Rimu Atkinson), who built PieFed in Python using the Flask framework specifically to address usability and technical complaints that limited adoption of Lemmy, an earlier Fediverse Reddit alternative. Because PieFed speaks ActivityPub, it federates directly with Lemmy and Mbin instances, meaning PieFed users can browse, post in, and comment on communities hosted on Lemmy servers without Lemmy needing to run any PieFed-specific code, and the reverse is also true. The project is not backed by a company; it is maintained largely by its founding developer and a small group of contributors, with the reference instance running at piefed.social and its source code hosted publicly. PieFed differentiates itself from Lemmy through specific product decisions aimed at usability: low-reputation comments are collapsed by default to reduce visible harassment, communities are organized into browsable topics, users with low reputation scores are visually flagged, and members can apply keyword filters to hide unwanted posts, echoing Reddit's old multireddit-style feed grouping. The software itself is entirely free to use and self-host, with no subscription tiers, consistent with its identity as a community-driven, decentralized alternative to corporate-owned social platforms. Target users are people seeking a Reddit-style discussion and link-sharing experience without a single company controlling content moderation or data, including communities that previously migrated to Lemmy during the 2023 Reddit API pricing controversy and are looking for a lighter-weight, more actively developed alternative. Its most direct competitors and comparable projects are Lemmy, the original Fediverse Reddit clone that PieFed federates with and was designed to improve upon; Mbin (formerly Kbin), another ActivityPub-based link aggregator; and, at a higher level, Reddit itself as the centralized incumbent that all of these Fediverse projects position themselves against. PieFed is generally described as newer and smaller than Lemmy but with a faster-moving codebase and features specifically aimed at fixing Lemmy's known pain points.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ecbe2f92-cfc5-4dba-ba88-7a0b655ae0ed';

