INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('738c4ff8-6bc1-45af-9978-423b14aba862', $q$Local library scanning$q$, $q$Automatically indexes photos and videos from existing folders, drives, or NAS volumes without requiring an upload step.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('738c4ff8-6bc1-45af-9978-423b14aba862', $q$Advanced de-duplication$q$, $q$Detects and merges duplicate or near-duplicate photos and videos imported from multiple sources (Plus tier).$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('738c4ff8-6bc1-45af-9978-423b14aba862', $q$Automatic video transcoding$q$, $q$Converts videos into web-friendly formats so they play back smoothly in any browser.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('738c4ff8-6bc1-45af-9978-423b14aba862', $q$Face tag extraction$q$, $q$Extracts and groups face tags already embedded in image metadata to help organize photos of people (Plus tier).$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('738c4ff8-6bc1-45af-9978-423b14aba862', $q$Portable library format$q$, $q$Stores the library in a cross-platform format that can be opened on Windows, macOS, Linux, or Docker without vendor lock-in.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('738c4ff8-6bc1-45af-9978-423b14aba862', $q$Keyword and metadata tagging$q$, $q$Supports keyword tagging and rich metadata handling for searching and filtering large collections.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('738c4ff8-6bc1-45af-9978-423b14aba862', $q$Mobile-friendly web UI$q$, $q$Provides a modern, responsive interface for browsing the library from phones and tablets on the local network.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('738c4ff8-6bc1-45af-9978-423b14aba862', $q$Free Lite tier permanently retains access to a user's own library, avoiding hard lock-in$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('738c4ff8-6bc1-45af-9978-423b14aba862', $q$Runs entirely on hardware the user controls, keeping personal photos off third-party clouds$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('738c4ff8-6bc1-45af-9978-423b14aba862', $q$Handles a very wide range of photo and video formats, including many RAW formats$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('738c4ff8-6bc1-45af-9978-423b14aba862', $q$Affordable Plus subscription compared to commercial cloud photo storage plans$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('738c4ff8-6bc1-45af-9978-423b14aba862', $q$Discounts available for open-source contributors and nonprofit workers$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('738c4ff8-6bc1-45af-9978-423b14aba862', $q$Requires the user to provide and maintain their own hardware or server$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('738c4ff8-6bc1-45af-9978-423b14aba862', $q$Advanced features like de-duplication and face tag extraction are gated behind the paid Plus tier$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('738c4ff8-6bc1-45af-9978-423b14aba862', $q$Smaller company and community than larger self-hosted alternatives, which may mean slower feature development$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('738c4ff8-6bc1-45af-9978-423b14aba862', $q$Initial library scan and indexing of very large archives can take significant time$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('738c4ff8-6bc1-45af-9978-423b14aba862', $q$Mobile apps and remote access require additional configuration compared to turnkey cloud services$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('738c4ff8-6bc1-45af-9978-423b14aba862', $q$Is PhotoStructure free to use?$q$, $q$Yes. The Lite tier is free and always retains the ability to open and browse a PhotoStructure library. A paid Plus subscription unlocks advanced features like de-duplication and face tag extraction.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('738c4ff8-6bc1-45af-9978-423b14aba862', $q$Does PhotoStructure require the cloud?$q$, $q$No. PhotoStructure is self-hosted software that runs on a user's own computer, NAS, or server, and does not require uploading photos to a third-party cloud.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('738c4ff8-6bc1-45af-9978-423b14aba862', $q$How much does PhotoStructure Plus cost?$q$, $q$PhotoStructure Plus costs 5 dollars per month or 42 dollars per year when billed annually, and covers a single household.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('738c4ff8-6bc1-45af-9978-423b14aba862', $q$Can I try PhotoStructure before paying?$q$, $q$Yes. New Plus subscriptions include a 15-day free trial that does not require a credit card.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('738c4ff8-6bc1-45af-9978-423b14aba862', $q$What happens to my library if I cancel Plus?$q$, $q$PhotoStructure's free Lite tier can always open an existing library, so canceling Plus does not lock users out of their own photos and videos.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('738c4ff8-6bc1-45af-9978-423b14aba862', $q$Does PhotoStructure support video files?$q$, $q$Yes. It supports a wide range of video formats and automatically transcodes videos for smooth playback in a web browser.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('738c4ff8-6bc1-45af-9978-423b14aba862', $q$Is PhotoStructure open source?$q$, $q$PhotoStructure is self-hosted but proprietary software, not an open-source project; it is subscriber-supported rather than funded through ads or data sharing.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('738c4ff8-6bc1-45af-9978-423b14aba862', $q$What platforms does PhotoStructure run on?$q$, $q$PhotoStructure can be installed on Windows, macOS, and Linux, and is also distributed as a Docker image for home server setups.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('738c4ff8-6bc1-45af-9978-423b14aba862', $q$Consolidating decades of family photos$q$, $q$Households with photos scattered across old hard drives, phone backups, and cloud exports can scan everything into one searchable, de-duplicated library.$q$, $q$Families and individuals with large personal photo archives$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('738c4ff8-6bc1-45af-9978-423b14aba862', $q$Privacy-conscious home server hosting$q$, $q$Users running a home server or NAS can self-host their photo library instead of relying on Google Photos or iCloud, keeping full control of their data.$q$, $q$Privacy-focused home lab and NAS owners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('738c4ff8-6bc1-45af-9978-423b14aba862', $q$Organizing a photographer's personal archive$q$, $q$Hobbyist and semi-professional photographers can index RAW and video files, tag them, and browse them locally without paying for cloud storage tiers.$q$, $q$Amateur and semi-professional photographers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('738c4ff8-6bc1-45af-9978-423b14aba862', $q$Lite$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Cross-platform, portable library format","Automatic volume scanning of existing folders","Automatic video transcoding","Keyword tagging","Image and video validation","Community forum support","Permanent access to browse your library"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('738c4ff8-6bc1-45af-9978-423b14aba862', $q$Plus$q$, $q$$5/month or $42/year$q$, $q$Monthly or annual$q$, NULL, $q$["Everything in Lite","Advanced de-duplication","Advanced metadata handling","Automatic organization","Face tag extraction","Modern mobile-friendly UI","Email and forum customer support","15-day free trial, no credit card required"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('738c4ff8-6bc1-45af-9978-423b14aba862', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$PhotoStructure is a self-hosted photo and video manager designed for people who want to organize decades of personal media without uploading everything to a third-party cloud service. It scans folders on a user's own computer, external drive, or home server, builds thumbnails and a searchable index, and presents the results through a web interface that can be accessed from any device on the local network.$q$, $q$The project was founded by Matthew McEachen in 2016 and is run as a small, subscriber-supported business rather than a venture-backed startup. PhotoStructure's stated philosophy is that a user's photo library should never be held hostage: the free Lite tier is permanently able to open any PhotoStructure library, even without a paid subscription.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('738c4ff8-6bc1-45af-9978-423b14aba862', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core capabilities include automatic volume scanning of existing photo and video folders, wide format support (including many RAW and video formats), automatic video transcoding for browser playback, keyword tagging, and image and video integrity validation to catch corrupted files.$q$, $q$The paid Plus tier adds advanced de-duplication that can detect near-duplicate images and videos across multiple import sources, deeper metadata extraction, automatic organization by date and location, and face tag extraction to help group photos of the same people.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('738c4ff8-6bc1-45af-9978-423b14aba862', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$PhotoStructure uses a freemium model. The Lite tier is free forever and always retains the ability to browse a user's library, even if a Plus subscription lapses. The Plus tier costs 5 dollars per month or 42 dollars per year (roughly 30 percent cheaper than paying monthly) and is licensed per household.$q$, $q$New Plus subscribers get a 15-day free trial with no credit card required. PhotoStructure also offers income-based coupons for users outside the US, free access for verified nonprofit and charity workers, and discount coupons (up to 100 percent) for maintainers and regular contributors to open-source projects that PhotoStructure depends on.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('738c4ff8-6bc1-45af-9978-423b14aba862', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4c103625-d77b-4769-a06c-01a9300cd28b', $q$Threaded discussion boards$q$, $q$Organizes conversations into forums, sub-forums, and topics with full moderation controls.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4c103625-d77b-4769-a06c-01a9300cd28b', $q$Private messaging$q$, $q$Built-in messaging system lets members communicate directly without leaving the forum.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4c103625-d77b-4769-a06c-01a9300cd28b', $q$Granular permissions$q$, $q$Fine-grained user and group permission system controls who can post, moderate, or access specific forums.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4c103625-d77b-4769-a06c-01a9300cd28b', $q$Custom styles and themes$q$, $q$Supports fully custom visual themes built by the community or designed in-house.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4c103625-d77b-4769-a06c-01a9300cd28b', $q$Extension framework$q$, $q$A modular extension system lets admins add polls, attachments, and third-party integrations without editing core code.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4c103625-d77b-4769-a06c-01a9300cd28b', $q$Built-in search engine$q$, $q$Native full-text search helps members and moderators find existing discussions quickly.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4c103625-d77b-4769-a06c-01a9300cd28b', $q$Multi-language support$q$, $q$Official and community language packs localize the interface into more than 50 languages.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4c103625-d77b-4769-a06c-01a9300cd28b', $q$Completely free and open source with no licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4c103625-d77b-4769-a06c-01a9300cd28b', $q$Extremely mature codebase with two decades of bug fixes and security patches$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4c103625-d77b-4769-a06c-01a9300cd28b', $q$Large ecosystem of free and paid styles, MODs, and extensions$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4c103625-d77b-4769-a06c-01a9300cd28b', $q$Full data ownership since the forum runs on infrastructure the admin controls$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4c103625-d77b-4769-a06c-01a9300cd28b', $q$Localized into dozens of languages by an active translator community$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4c103625-d77b-4769-a06c-01a9300cd28b', $q$Strong built-in moderation and permission tools out of the box$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4c103625-d77b-4769-a06c-01a9300cd28b', $q$Requires self-hosting and ongoing server maintenance, unlike hosted SaaS forum tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4c103625-d77b-4769-a06c-01a9300cd28b', $q$Default interface can feel dated compared to newer platforms like Discourse$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4c103625-d77b-4769-a06c-01a9300cd28b', $q$Security depends on the administrator keeping the installation and extensions patched$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4c103625-d77b-4769-a06c-01a9300cd28b', $q$Setting up advanced customizations often requires PHP and template knowledge$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4c103625-d77b-4769-a06c-01a9300cd28b', $q$No official managed cloud hosting plan directly from phpBB Limited$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4c103625-d77b-4769-a06c-01a9300cd28b', $q$Mobile experience relies on responsive styles rather than a native app$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4c103625-d77b-4769-a06c-01a9300cd28b', $q$Is phpBB free to use?$q$, $q$Yes. phpBB is released under the GNU General Public License and is free to download, install, and modify on your own server.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4c103625-d77b-4769-a06c-01a9300cd28b', $q$Who maintains phpBB?$q$, $q$phpBB is maintained by phpBB Limited, a UK-based company that holds the trademark, together with a large community of volunteer developers and translators.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4c103625-d77b-4769-a06c-01a9300cd28b', $q$Do I need to know PHP to use phpBB?$q$, $q$No coding knowledge is required for basic setup and administration, but customizing templates, styles, or extensions typically requires PHP and HTML familiarity.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4c103625-d77b-4769-a06c-01a9300cd28b', $q$What database does phpBB support?$q$, $q$phpBB supports MySQL, MariaDB, PostgreSQL, SQLite, and other common database backends.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4c103625-d77b-4769-a06c-01a9300cd28b', $q$Can I import an existing forum into phpBB?$q$, $q$phpBB includes conversion tools for migrating from several other forum platforms, and community-built converters exist for many additional systems.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4c103625-d77b-4769-a06c-01a9300cd28b', $q$Is phpBB still actively developed?$q$, $q$Yes. phpBB continues to receive updates from phpBB Limited and its volunteer contributor community, including security patches and new extensions.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4c103625-d77b-4769-a06c-01a9300cd28b', $q$How is phpBB different from Discourse?$q$, $q$phpBB is a traditional, self-hosted, PHP-based bulletin board, while Discourse is a more modern JavaScript-based discussion platform; phpBB tends to offer more granular self-hosted control and a larger legacy plugin ecosystem.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4c103625-d77b-4769-a06c-01a9300cd28b', $q$Does phpBB offer hosted plans?$q$, $q$phpBB Limited does not sell an official managed hosting plan; administrators typically self-host phpBB on their own web hosting or server infrastructure.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4c103625-d77b-4769-a06c-01a9300cd28b', $q$Hobbyist and interest-based communities$q$, $q$Enthusiast groups, from gaming clans to hobby clubs, use phpBB to run free, fully customizable discussion boards for their members.$q$, $q$Community organizers and hobbyist webmasters$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4c103625-d77b-4769-a06c-01a9300cd28b', $q$Product and technical support forums$q$, $q$Software vendors and open-source projects run self-hosted phpBB forums so users can ask questions and search a permanent knowledge base.$q$, $q$Software companies and open-source project maintainers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4c103625-d77b-4769-a06c-01a9300cd28b', $q$Long-running niche communities needing data ownership$q$, $q$Organizations that want full control over their community's data and moderation policy, without depending on a third-party SaaS platform, deploy phpBB on their own servers.$q$, $q$Organizations prioritizing data ownership and self-hosting$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4c103625-d77b-4769-a06c-01a9300cd28b', $q$Self-Hosted$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full phpBB forum software","Unlimited forums, topics, and users (subject to server capacity)","Custom styles and themes","Extension framework","Community support via phpBB.com forums","GNU General Public License, self-hosted"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4c103625-d77b-4769-a06c-01a9300cd28b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$phpBB is free, open-source forum software originally created by James Atkinson in 2000 and now maintained by phpBB Limited alongside a large volunteer contributor community. It is one of the oldest and most widely deployed bulletin board systems on the internet, powering everything from small hobbyist communities to large support and gaming forums.$q$, $q$Because it is self-hosted, administrators install phpBB on their own web server and database, giving them full ownership of their community's data, moderation policies, and customization, in contrast to hosted forum SaaS products.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4c103625-d77b-4769-a06c-01a9300cd28b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$phpBB provides threaded discussion boards, private messaging, granular user and group permissions, a built-in search engine, and extensive moderation and reporting tools. Its styling system supports fully custom themes, and its extension framework allows administrators to add features like polls, attachments, and third-party integrations.$q$, $q$The platform has been localized into more than 50 languages by community translators and supports a wide range of authentication methods, including LDAP and OAuth-based logins through official and community extensions.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4c103625-d77b-4769-a06c-01a9300cd28b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$phpBB itself is completely free to download and self-host under the GNU General Public License. There is no official paid tier for the core software.$q$, $q$Costs come from external factors: web hosting, a domain name, and optional premium styles or extensions sold by third-party developers in the phpBB community. Organizations that want managed hosting typically use a separate third-party hosting provider rather than an official phpBB-branded hosted plan.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4c103625-d77b-4769-a06c-01a9300cd28b', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4c103625-d77b-4769-a06c-01a9300cd28b', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('42a75ad3-068c-492e-a658-dfdeda416a65', $q$IPv4 and IPv6 subnet management$q$, $q$Tracks and organizes subnets across sections and groups for both IPv4 and IPv6 address space.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('42a75ad3-068c-492e-a658-dfdeda416a65', $q$Visual subnet maps$q$, $q$Displays subnet utilization visually with automatic indicators for free and used address space.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('42a75ad3-068c-492e-a658-dfdeda416a65', $q$VLAN and VRF tracking$q$, $q$Documents VLAN assignments and VRF context alongside IP address allocations.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('42a75ad3-068c-492e-a658-dfdeda416a65', $q$Subnet scanning$q$, $q$Scans configured subnets to detect live hosts and flag discrepancies against documented records.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('42a75ad3-068c-492e-a658-dfdeda416a65', $q$REST API$q$, $q$Provides a full REST API for automating IP address allocation and integrating with other network tools.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('42a75ad3-068c-492e-a658-dfdeda416a65', $q$PowerDNS integration$q$, $q$Syncs DNS records with a PowerDNS server directly from IP address entries.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('42a75ad3-068c-492e-a658-dfdeda416a65', $q$Enterprise authentication$q$, $q$Supports login via Active Directory, LDAP, and RADIUS for centralized access control.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('42a75ad3-068c-492e-a658-dfdeda416a65', $q$Completely free and open source with no licensing costs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('42a75ad3-068c-492e-a658-dfdeda416a65', $q$Full IPv4 and IPv6 support with VLAN and VRF tracking$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('42a75ad3-068c-492e-a658-dfdeda416a65', $q$REST API enables automation and integration with existing network tooling$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('42a75ad3-068c-492e-a658-dfdeda416a65', $q$Lightweight installation that runs well on modest server hardware$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('42a75ad3-068c-492e-a658-dfdeda416a65', $q$Active community development and regular releases on GitHub$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('42a75ad3-068c-492e-a658-dfdeda416a65', $q$Granular permission controls for multi-team environments$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('42a75ad3-068c-492e-a658-dfdeda416a65', $q$Requires self-hosting and ongoing maintenance since there is no managed cloud offering$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('42a75ad3-068c-492e-a658-dfdeda416a65', $q$No official commercial support contract or SLA available$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('42a75ad3-068c-492e-a658-dfdeda416a65', $q$Interface feels more utilitarian than modern commercial IPAM dashboards$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('42a75ad3-068c-492e-a658-dfdeda416a65', $q$Focuses narrowly on IP address management rather than broader network monitoring or configuration management$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('42a75ad3-068c-492e-a658-dfdeda416a65', $q$Relies on community documentation and forums for troubleshooting rather than a dedicated support team$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('42a75ad3-068c-492e-a658-dfdeda416a65', $q$Is phpIPAM free to use?$q$, $q$Yes. phpIPAM is a free, open-source IP address management tool with no licensing fees or paid tiers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('42a75ad3-068c-492e-a658-dfdeda416a65', $q$Does phpIPAM support IPv6?$q$, $q$Yes. phpIPAM fully supports both IPv4 and IPv6 subnet and address management.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('42a75ad3-068c-492e-a658-dfdeda416a65', $q$Can phpIPAM integrate with automation tools?$q$, $q$Yes. phpIPAM provides a REST API that can be used with automation and configuration management tools such as Ansible and Terraform.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('42a75ad3-068c-492e-a658-dfdeda416a65', $q$What are the hosting requirements for phpIPAM?$q$, $q$phpIPAM typically runs on a Linux server with Apache or nginx, PHP, and a MySQL or MariaDB database; it is also available as a Docker image.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('42a75ad3-068c-492e-a658-dfdeda416a65', $q$Does phpIPAM support DNS management?$q$, $q$phpIPAM integrates with PowerDNS to keep DNS records in sync with documented IP address allocations.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('42a75ad3-068c-492e-a658-dfdeda416a65', $q$How is phpIPAM different from NetBox?$q$, $q$phpIPAM focuses specifically on IP address and subnet management with a simpler feature set, while NetBox offers broader data-center infrastructure modeling in addition to IPAM.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('42a75ad3-068c-492e-a658-dfdeda416a65', $q$Who maintains phpIPAM?$q$, $q$phpIPAM is maintained by an open-source community of volunteer contributors through its GitHub repository rather than a commercial company.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('42a75ad3-068c-492e-a658-dfdeda416a65', $q$Can I authenticate phpIPAM against Active Directory?$q$, $q$Yes. phpIPAM supports authentication via Active Directory, LDAP, and RADIUS in addition to local accounts.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('42a75ad3-068c-492e-a658-dfdeda416a65', $q$Enterprise network address documentation$q$, $q$IT and network teams use phpIPAM to maintain an authoritative record of subnet allocations, VLANs, and host assignments across their infrastructure.$q$, $q$Network administrators and IT operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('42a75ad3-068c-492e-a658-dfdeda416a65', $q$Service provider IP allocation tracking$q$, $q$Hosting and telecom providers use phpIPAM to track customer IP block assignments and avoid address conflicts as their network grows.$q$, $q$Internet and hosting service providers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('42a75ad3-068c-492e-a658-dfdeda416a65', $q$Homelab and self-hosting address tracking$q$, $q$Self-hosting enthusiasts running homelabs with multiple VLANs and subnets use phpIPAM to keep track of device and subnet assignments for free.$q$, $q$Homelab operators and self-hosting enthusiasts$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('42a75ad3-068c-492e-a658-dfdeda416a65', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full IPv4 and IPv6 address management","Subnet, VLAN and VRF tracking","Subnet scanning","REST API access","PowerDNS integration","Active Directory, LDAP and RADIUS authentication","Community support via GitHub and forums"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('42a75ad3-068c-492e-a658-dfdeda416a65', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$phpIPAM is an open-source IP address management tool that helps network teams document and organize IPv4 and IPv6 address space, subnets, VLANs, and VRFs through a web-based interface. It is built on PHP with a MySQL backend and is self-hosted on the user's own server infrastructure.$q$, $q$The project is maintained by a community of contributors rather than a commercial vendor, and it is distributed free of charge under an open-source license, making it a common choice for organizations that want IPAM functionality without licensing fees.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('42a75ad3-068c-492e-a658-dfdeda416a65', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$phpIPAM covers the core needs of IP address tracking: subnet and VLAN management, visual subnet utilization maps, automated subnet scanning to detect active hosts, and NAT documentation. It also integrates with PowerDNS for DNS record management and supports authentication against Active Directory, LDAP, and RADIUS.$q$, $q$For automation-focused teams, phpIPAM exposes a REST API that can be used to script address allocation, integrate with configuration management tools, or feed IP inventory data into other network systems.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('42a75ad3-068c-492e-a658-dfdeda416a65', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$phpIPAM is completely free and open source, with no paid tiers, licensing fees, or usage limits from the project itself. Organizations only pay for the infrastructure needed to host it, such as a Linux server and database.$q$, $q$Because there is no official hosted or commercial edition, teams that want managed hosting must arrange it through third-party hosting providers, who set their own independent pricing for infrastructure and support.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('42a75ad3-068c-492e-a658-dfdeda416a65', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('42a75ad3-068c-492e-a658-dfdeda416a65', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05c5746c-f3a3-47a9-b647-2b4ab14ad200', $q$Campaign management$q$, $q$Create, schedule, and send newsletter campaigns to segmented subscriber lists.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05c5746c-f3a3-47a9-b647-2b4ab14ad200', $q$Subscriber list management$q$, $q$Organize subscribers into lists with custom fields and segmentation criteria.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05c5746c-f3a3-47a9-b647-2b4ab14ad200', $q$Autoresponders and drip campaigns$q$, $q$Automate follow-up email sequences triggered by subscription events or schedules.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05c5746c-f3a3-47a9-b647-2b4ab14ad200', $q$Click and open tracking$q$, $q$Tracks email opens and link clicks to measure campaign engagement.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05c5746c-f3a3-47a9-b647-2b4ab14ad200', $q$Bounce and unsubscribe management$q$, $q$Automatically processes bounces and unsubscribe requests to keep lists clean.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05c5746c-f3a3-47a9-b647-2b4ab14ad200', $q$API and plugin extensibility$q$, $q$Exposes an API and plugin system for integrating phpList with other systems or extending functionality.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05c5746c-f3a3-47a9-b647-2b4ab14ad200', $q$Self-hosted or hosted deployment$q$, $q$Can be run free on a user's own server or through phpList's paid hosted service.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('05c5746c-f3a3-47a9-b647-2b4ab14ad200', $q$Core software is free and open source, avoiding per-contact SaaS pricing at scale$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('05c5746c-f3a3-47a9-b647-2b4ab14ad200', $q$Self-hosting gives full control and ownership of subscriber data$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('05c5746c-f3a3-47a9-b647-2b4ab14ad200', $q$Hosted plans are inexpensive compared to many mainstream email marketing SaaS tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('05c5746c-f3a3-47a9-b647-2b4ab14ad200', $q$Long track record with roughly 75,000 organizations reported using the platform$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('05c5746c-f3a3-47a9-b647-2b4ab14ad200', $q$API and plugin system support custom integrations$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('05c5746c-f3a3-47a9-b647-2b4ab14ad200', $q$Available in multiple languages for international teams$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('05c5746c-f3a3-47a9-b647-2b4ab14ad200', $q$Self-hosted setup requires technical skill to configure a reliable mail server$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('05c5746c-f3a3-47a9-b647-2b4ab14ad200', $q$Interface and campaign editor feel less polished than modern SaaS competitors like Mailchimp$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('05c5746c-f3a3-47a9-b647-2b4ab14ad200', $q$Deliverability depends heavily on the user's own server reputation when self-hosted$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('05c5746c-f3a3-47a9-b647-2b4ab14ad200', $q$Fewer built-in marketing automation and design templates than larger commercial platforms$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('05c5746c-f3a3-47a9-b647-2b4ab14ad200', $q$Support for the free self-hosted edition relies mainly on community resources$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05c5746c-f3a3-47a9-b647-2b4ab14ad200', $q$Is phpList free to use?$q$, $q$Yes, the core phpList software is free to download and self-host. phpList also offers a paid hosted service for organizations that do not want to manage their own mail server.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05c5746c-f3a3-47a9-b647-2b4ab14ad200', $q$Who created phpList?$q$, $q$phpList was created by Michiel Dethmers, who began developing it in 2000 and led the project for 15 years before Sam Tuke became CEO of phpList Ltd in 2015.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05c5746c-f3a3-47a9-b647-2b4ab14ad200', $q$How much does phpList's hosted service cost?$q$, $q$Hosted plans start at around 1 dollar per month, billed per subscriber or per message, with higher-volume plans available for larger sending needs.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05c5746c-f3a3-47a9-b647-2b4ab14ad200', $q$Can I self-host phpList?$q$, $q$Yes. phpList is open source and can be installed on your own web hosting, provided you also have a working mail server capable of delivering campaigns.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05c5746c-f3a3-47a9-b647-2b4ab14ad200', $q$Does phpList support automation?$q$, $q$Yes, phpList supports autoresponders and drip campaigns that trigger automatically based on subscriber actions or schedules.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05c5746c-f3a3-47a9-b647-2b4ab14ad200', $q$How many organizations use phpList?$q$, $q$phpList reports that around 75,000 organizations across 35 countries use the platform.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05c5746c-f3a3-47a9-b647-2b4ab14ad200', $q$Does phpList have an API?$q$, $q$Yes, phpList provides an API and plugin system for integrating with other tools and extending its functionality.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05c5746c-f3a3-47a9-b647-2b4ab14ad200', $q$How does phpList compare to Mailchimp?$q$, $q$phpList is open source and can be self-hosted for free, while Mailchimp is a hosted-only SaaS platform; phpList generally appeals to users who want data control or lower costs at scale, while Mailchimp offers a more polished interface and broader marketing features.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('05c5746c-f3a3-47a9-b647-2b4ab14ad200', $q$Nonprofit and NGO email campaigns$q$, $q$Nonprofits with tight budgets self-host phpList to send donor and community newsletters without per-contact SaaS fees.$q$, $q$Nonprofits and NGOs$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('05c5746c-f3a3-47a9-b647-2b4ab14ad200', $q$Developer-managed newsletter infrastructure$q$, $q$Development teams that already manage their own servers use phpList's API to integrate newsletter sending directly into their applications.$q$, $q$Developers and technical teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('05c5746c-f3a3-47a9-b647-2b4ab14ad200', $q$Cost-conscious large-list publishers$q$, $q$Publishers and community sites with large subscriber lists use phpList's hosted per-message pricing to avoid the high per-contact costs of mainstream SaaS email tools.$q$, $q$Publishers and community website operators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('05c5746c-f3a3-47a9-b647-2b4ab14ad200', $q$Self-Hosted$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full phpList software, self-hosted","Campaign and subscriber management","Autoresponders and drip campaigns","API and plugin access","Requires own web hosting and mail server","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('05c5746c-f3a3-47a9-b647-2b4ab14ad200', $q$Hosted (phpList.com)$q$, $q$From $1/month$q$, $q$Monthly, pay per subscriber or per message$q$, NULL, $q$["Managed hosting, no server setup required","Campaign and subscriber management","Bounce and unsubscribe handling","Scales up to sending a million messages a month from about $8/month","Professional support options available"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('05c5746c-f3a3-47a9-b647-2b4ab14ad200', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$phpList is open-source email newsletter and marketing software that organizations use to send campaigns, manage subscriber lists, and run drip and autoresponder sequences. It began as a project by Michiel Dethmers in 2000 and is now stewarded by phpList Limited, a UK company.$q$, $q$The software can be self-hosted for free on a user's own server, or run through phpList's hosted service for teams that do not want to manage their own mail infrastructure. This dual model lets phpList serve both budget-conscious self-hosters and organizations that prefer a managed solution.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('05c5746c-f3a3-47a9-b647-2b4ab14ad200', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$phpList supports campaign management with scheduling, subscriber list segmentation with custom fields, autoresponders and drip campaigns, and click and open tracking for measuring engagement. Bounce handling and unsubscribe management help maintain list hygiene and sender reputation.$q$, $q$Developers can extend phpList through its API and plugin system, and the self-hosted edition gives full access to the underlying database and mail configuration for advanced customization.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('05c5746c-f3a3-47a9-b647-2b4ab14ad200', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core phpList software is free to download and self-host, though running it well requires appropriate web hosting and a working outbound mail server capable of reliable delivery.$q$, $q$For organizations that prefer not to manage their own infrastructure, phpList's hosted service offers paid plans starting at roughly 1 dollar per month, billed per subscriber or per message, with volume plans that bring the cost of sending a million messages a month down to around 8 dollars per month.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('05c5746c-f3a3-47a9-b647-2b4ab14ad200', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('05c5746c-f3a3-47a9-b647-2b4ab14ad200', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('08450324-4200-4667-af14-f12d8180794b', $q$Network-wide DNS ad blocking$q$, $q$Blocks ads and trackers for every device on the network by filtering DNS requests, without needing per-device software.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('08450324-4200-4667-af14-f12d8180794b', $q$Configurable blocklists and allowlists$q$, $q$Supports adding, removing, and customizing blocklists and allowlists to fine-tune what gets blocked.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('08450324-4200-4667-af14-f12d8180794b', $q$Built-in DHCP server$q$, $q$Can optionally act as the network's DHCP server in addition to its DNS filtering role.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('08450324-4200-4667-af14-f12d8180794b', $q$Real-time web dashboard$q$, $q$Provides a web-based admin interface showing live query statistics, top blocked domains, and per-client activity.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('08450324-4200-4667-af14-f12d8180794b', $q$Per-client blocking rules$q$, $q$Allows administrators to apply different blocking rules to specific devices on the network.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('08450324-4200-4667-af14-f12d8180794b', $q$Encrypted upstream DNS support$q$, $q$Can be configured to forward queries to upstream resolvers over DNS-over-HTTPS or DNS-over-TLS for added privacy.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('08450324-4200-4667-af14-f12d8180794b', $q$Low-power hardware support$q$, $q$Designed to run efficiently on a Raspberry Pi as well as standard Linux servers and Docker containers.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('08450324-4200-4667-af14-f12d8180794b', $q$Completely free and open source with no subscription required$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('08450324-4200-4667-af14-f12d8180794b', $q$Blocks ads and trackers network-wide, covering devices that cannot run browser extensions$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('08450324-4200-4667-af14-f12d8180794b', $q$Runs well on inexpensive, low-power hardware like a Raspberry Pi$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('08450324-4200-4667-af14-f12d8180794b', $q$Large, active community maintaining blocklists and documentation$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('08450324-4200-4667-af14-f12d8180794b', $q$Web dashboard gives clear visibility into network-wide DNS activity$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('08450324-4200-4667-af14-f12d8180794b', $q$Can double as a DHCP server, simplifying home network setups$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('08450324-4200-4667-af14-f12d8180794b', $q$Does not block ads embedded within the same domain as the content itself (e.g. some in-app ads)$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('08450324-4200-4667-af14-f12d8180794b', $q$Requires basic networking knowledge to configure DNS or DHCP settings correctly$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('08450324-4200-4667-af14-f12d8180794b', $q$A single Pi-hole instance is a single point of failure for network DNS unless a backup is configured$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('08450324-4200-4667-af14-f12d8180794b', $q$Some sites detect and work around DNS-level ad blocking, requiring blocklist maintenance$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('08450324-4200-4667-af14-f12d8180794b', $q$No official commercial support channel since it is a volunteer-run project$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('08450324-4200-4667-af14-f12d8180794b', $q$Is Pi-hole free?$q$, $q$Yes, Pi-hole is completely free and open source. The project is sustained through voluntary donations rather than software sales or subscriptions.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('08450324-4200-4667-af14-f12d8180794b', $q$Do I need a Raspberry Pi to run Pi-hole?$q$, $q$No. While Pi-hole was originally designed for the Raspberry Pi, it can run on most Linux systems, virtual machines, and as a Docker container.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('08450324-4200-4667-af14-f12d8180794b', $q$How does Pi-hole block ads?$q$, $q$Pi-hole works as a DNS sinkhole, comparing every DNS query on the network against blocklists and refusing to resolve domains known to serve ads or trackers.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('08450324-4200-4667-af14-f12d8180794b', $q$Does Pi-hole block ads on every device?$q$, $q$Yes, because it filters at the network's DNS level, Pi-hole blocks ads and trackers for any device configured to use it as a DNS server, including phones, smart TVs, and IoT devices.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('08450324-4200-4667-af14-f12d8180794b', $q$Who created Pi-hole?$q$, $q$Pi-hole was created by Jacob Salmela in June 2014 as an open-source Raspberry Pi alternative to a commercial ad-blocking device called AdTrap.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('08450324-4200-4667-af14-f12d8180794b', $q$Can Pi-hole replace my router's DHCP server?$q$, $q$Yes, Pi-hole includes an optional built-in DHCP server that can replace or work alongside your router's DHCP functionality.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('08450324-4200-4667-af14-f12d8180794b', $q$How is Pi-hole different from AdGuard Home?$q$, $q$Both are free, open-source DNS-level ad blockers with similar functionality; Pi-hole has a longer track record and larger community, while AdGuard Home is often noted for a slightly different default interface and feature set.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('08450324-4200-4667-af14-f12d8180794b', $q$Does Pi-hole protect my privacy from all tracking?$q$, $q$Pi-hole blocks known ad and tracking domains at the DNS level, but it does not replace a VPN or encrypt your traffic, and some tracking that does not rely on blocklisted domains may not be blocked.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('08450324-4200-4667-af14-f12d8180794b', $q$Home network ad blocking$q$, $q$Home users install Pi-hole on a Raspberry Pi or home server to block ads and trackers across every device on their home Wi-Fi network.$q$, $q$Home users and privacy-conscious households$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('08450324-4200-4667-af14-f12d8180794b', $q$Homelab and self-hosting infrastructure$q$, $q$Self-hosting enthusiasts run Pi-hole alongside other self-hosted services as part of a broader homelab DNS and network management setup.$q$, $q$Homelab operators and self-hosting enthusiasts$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('08450324-4200-4667-af14-f12d8180794b', $q$Small office network protection$q$, $q$Small offices deploy Pi-hole to reduce ad and tracker traffic across office devices without purchasing a commercial ad-blocking appliance.$q$, $q$Small businesses and small office IT admins$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('08450324-4200-4667-af14-f12d8180794b', $q$Self-Hosted$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Network-wide DNS ad and tracker blocking","Configurable blocklists and allowlists","Optional built-in DHCP server","Web-based admin dashboard","Per-client blocking rules","Runs on Raspberry Pi, Linux, or Docker","Community support and donation-funded development"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('08450324-4200-4667-af14-f12d8180794b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Pi-hole is a free, open-source DNS sinkhole that blocks advertisements and trackers for every device on a network by intercepting and filtering DNS queries before they reach ad and tracking domains. It was created by Jacob Salmela in 2014 as a lightweight Raspberry Pi project and has grown into one of the most widely deployed self-hosted networking tools.$q$, $q$Because Pi-hole operates at the DNS level rather than inside individual browsers, it blocks ads and trackers across every device connected to the network, including smart TVs, phones, and IoT devices that cannot run browser extensions.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('08450324-4200-4667-af14-f12d8180794b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Pi-hole replaces or supplements a network's existing DNS server, comparing every DNS query against configurable blocklists and returning a null response for matched domains. It can also function as a DHCP server, and it ships with a web-based dashboard that shows real-time query logs, blocked-domain statistics, and per-client activity.$q$, $q$Administrators can add custom blocklists and allowlists, create per-client blocking rules, and run Pi-hole in recursive mode with upstream DNS resolvers of their choosing, including encrypted DNS-over-HTTPS or DNS-over-TLS providers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('08450324-4200-4667-af14-f12d8180794b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Pi-hole is completely free and open source, with no paid tiers, subscriptions, or license fees for the software itself. It runs on inexpensive hardware such as a Raspberry Pi, or on any standard Linux machine or Docker host.$q$, $q$The project sustains itself through voluntary donations via GitHub Sponsors and Patreon, along with affiliate partnerships, rather than charging users for the software or offering a commercial edition.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('08450324-4200-4667-af14-f12d8180794b', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('08450324-4200-4667-af14-f12d8180794b', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d7aacfb-24f7-4b69-a710-ff2942eeaaa7', $q$URL-based image resizing API$q$, $q$Resizes and filters images simply by editing parameters in the file's URL, with no separate API call needed.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d7aacfb-24f7-4b69-a710-ff2942eeaaa7', $q$Automatic EXIF stripping$q$, $q$Removes EXIF metadata, including GPS location and camera details, from every uploaded image automatically.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d7aacfb-24f7-4b69-a710-ff2942eeaaa7', $q$File-based, database-free architecture$q$, $q$Stores all content as files on disk, avoiding the need to set up and maintain a separate database.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d7aacfb-24f7-4b69-a710-ff2942eeaaa7', $q$Video and GIF handling$q$, $q$Converts GIFs to MP4 and ensures uploaded videos are properly encoded for web playback.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d7aacfb-24f7-4b69-a710-ff2942eeaaa7', $q$WebP conversion$q$, $q$Automatically converts JPG and PNG images to the more efficient WebP format.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d7aacfb-24f7-4b69-a710-ff2942eeaaa7', $q$Upload deduplication$q$, $q$Detects duplicate uploads and avoids storing multiple copies of the same file.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d7aacfb-24f7-4b69-a710-ff2942eeaaa7', $q$Pastebin-style text hosting$q$, $q$Supports hosting plain text snippets in addition to images and videos.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9d7aacfb-24f7-4b69-a710-ff2942eeaaa7', $q$Completely free and open source with no licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9d7aacfb-24f7-4b69-a710-ff2942eeaaa7', $q$Database-free architecture makes deployment and backups simple$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9d7aacfb-24f7-4b69-a710-ff2942eeaaa7', $q$Automatic EXIF stripping protects user privacy on uploaded photos$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9d7aacfb-24f7-4b69-a710-ff2942eeaaa7', $q$URL-based resizing API is developer-friendly and easy to integrate$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9d7aacfb-24f7-4b69-a710-ff2942eeaaa7', $q$Deduplication reduces storage use for repeated uploads$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9d7aacfb-24f7-4b69-a710-ff2942eeaaa7', $q$Lightweight enough to run on a small VPS or home server$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9d7aacfb-24f7-4b69-a710-ff2942eeaaa7', $q$Smaller community and slower update cadence than larger commercial hosting scripts$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9d7aacfb-24f7-4b69-a710-ff2942eeaaa7', $q$Lacks a polished admin dashboard compared to commercial alternatives like Chevereto$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9d7aacfb-24f7-4b69-a710-ff2942eeaaa7', $q$No official managed hosting option, so self-hosting expertise is required$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9d7aacfb-24f7-4b69-a710-ff2942eeaaa7', $q$Limited built-in user account or gallery management features$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9d7aacfb-24f7-4b69-a710-ff2942eeaaa7', $q$Documentation is community-maintained and can lag behind newer releases$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d7aacfb-24f7-4b69-a710-ff2942eeaaa7', $q$Is PictShare free?$q$, $q$Yes, PictShare is free and open source under the Apache-2.0 license, with no paid tiers or subscription fees.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d7aacfb-24f7-4b69-a710-ff2942eeaaa7', $q$Who makes PictShare?$q$, $q$PictShare is built and maintained by Christian Haschek's company, Haschek Solutions, based in Austria.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d7aacfb-24f7-4b69-a710-ff2942eeaaa7', $q$Does PictShare require a database?$q$, $q$No. PictShare is entirely file-based and does not require a separate database to run.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d7aacfb-24f7-4b69-a710-ff2942eeaaa7', $q$Does PictShare strip metadata from photos?$q$, $q$Yes, PictShare automatically removes EXIF metadata, including GPS location and camera model information, from every uploaded image.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d7aacfb-24f7-4b69-a710-ff2942eeaaa7', $q$Can I resize images without a separate API call?$q$, $q$Yes. PictShare lets you resize and filter images just by editing parameters directly in the file's URL.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d7aacfb-24f7-4b69-a710-ff2942eeaaa7', $q$Does PictShare support video uploads?$q$, $q$Yes, PictShare supports MP4 video hosting and can convert GIFs to MP4 for more efficient playback.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d7aacfb-24f7-4b69-a710-ff2942eeaaa7', $q$What license is PictShare released under?$q$, $q$PictShare is released under the Apache-2.0 open-source license.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d7aacfb-24f7-4b69-a710-ff2942eeaaa7', $q$How is PictShare different from Chevereto?$q$, $q$PictShare is a free, file-based, database-free image and video host with a URL-driven API, while Chevereto is a more full-featured image gallery script that offers both free and paid commercial licenses with a fuller admin dashboard.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9d7aacfb-24f7-4b69-a710-ff2942eeaaa7', $q$Self-hosted image CDN for developers$q$, $q$Developers embed PictShare into their own applications as a lightweight, self-hosted image and video CDN with URL-based resizing.$q$, $q$Developers building applications that need image hosting$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9d7aacfb-24f7-4b69-a710-ff2942eeaaa7', $q$Privacy-focused personal photo sharing$q$, $q$Individuals who want to share photos without leaking EXIF metadata like GPS location use PictShare to host and share images safely.$q$, $q$Privacy-conscious individuals sharing personal photos$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9d7aacfb-24f7-4b69-a710-ff2942eeaaa7', $q$Bloggers and content creators hosting their own media$q$, $q$Bloggers and site owners self-host PictShare to serve images and short videos from their own infrastructure instead of a third-party host.$q$, $q$Bloggers and independent content creators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9d7aacfb-24f7-4b69-a710-ff2942eeaaa7', $q$Self-Hosted$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Image, video, and text hosting","URL-based resizing and filtering API","Automatic EXIF stripping","GIF to MP4 and JPG/PNG to WebP conversion","Upload deduplication","File-based, no database required","Apache-2.0 open-source license"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9d7aacfb-24f7-4b69-a710-ff2942eeaaa7', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$PictShare is a free, open-source, self-hosted image, video, and text hosting tool built by Christian Haschek's Haschek Solutions in Austria. It is designed to be a simple, self-owned alternative to third-party image hosts, letting users or developers run their own lightweight CDN for images and short videos.$q$, $q$The tool is built in PHP, stores everything as files rather than in a database, and is distributed on GitHub under the Apache-2.0 open-source license, making it straightforward to deploy on a small VPS or home server.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9d7aacfb-24f7-4b69-a710-ff2942eeaaa7', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$PictShare's defining feature is its URL-based resizing and filtering API: users can resize images, apply filters, and convert formats simply by modifying the URL of an uploaded file, without a separate API call. It automatically converts GIFs to MP4 and JPG/PNG images to WebP for more efficient delivery.$q$, $q$For privacy, PictShare automatically strips EXIF metadata, including GPS coordinates and camera information, from every uploaded image. It also deduplicates identical uploads to save storage space and includes pastebin-style text hosting and URL shortening.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9d7aacfb-24f7-4b69-a710-ff2942eeaaa7', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$PictShare is completely free and open source, with no paid tiers, licenses, or subscription fees. Anyone can download the code from GitHub and self-host it at no cost beyond their own server infrastructure.$q$, $q$Because there is no commercial edition, all support is community-based through GitHub issues and documentation rather than a formal paid support contract.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9d7aacfb-24f7-4b69-a710-ff2942eeaaa7', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9d7aacfb-24f7-4b69-a710-ff2942eeaaa7', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ecbe2f92-cfc5-4dba-ba88-7a0b655ae0ed', $q$ActivityPub federation with Lemmy and Mbin$q$, $q$Interoperates directly with Lemmy and Mbin communities over ActivityPub without requiring identical software on every server.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ecbe2f92-cfc5-4dba-ba88-7a0b655ae0ed', $q$Topic-organized communities$q$, $q$Groups communities into browsable topics to make content discovery easier than a flat community list.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ecbe2f92-cfc5-4dba-ba88-7a0b655ae0ed', $q$Automatic low-score comment collapsing$q$, $q$Collapses comments with low scores by default to reduce visibility of harassment or low-quality replies.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ecbe2f92-cfc5-4dba-ba88-7a0b655ae0ed', $q$Keyword post filtering$q$, $q$Lets users hide posts containing specific keywords, similar to a personalized content filter.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ecbe2f92-cfc5-4dba-ba88-7a0b655ae0ed', $q$Reputation indicators$q$, $q$Flags users with a history of low-reputation contributions to help others assess comment quality at a glance.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ecbe2f92-cfc5-4dba-ba88-7a0b655ae0ed', $q$Feed grouping$q$, $q$Supports grouping multiple communities into custom feeds, echoing Reddit's old multireddit feature.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ecbe2f92-cfc5-4dba-ba88-7a0b655ae0ed', $q$Self-hostable instance software$q$, $q$Organizations or individuals can run their own PieFed instance and federate it with the wider Fediverse.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ecbe2f92-cfc5-4dba-ba88-7a0b655ae0ed', $q$Completely free and open source with no subscription required$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ecbe2f92-cfc5-4dba-ba88-7a0b655ae0ed', $q$Federates with Lemmy and Mbin, giving access to a much larger pool of communities$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ecbe2f92-cfc5-4dba-ba88-7a0b655ae0ed', $q$Built specifically to fix known usability complaints about Lemmy$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ecbe2f92-cfc5-4dba-ba88-7a0b655ae0ed', $q$Comment collapsing and reputation indicators help surface higher-quality discussion$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ecbe2f92-cfc5-4dba-ba88-7a0b655ae0ed', $q$Not controlled by a single corporation, reducing risk of sudden policy or pricing changes$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ecbe2f92-cfc5-4dba-ba88-7a0b655ae0ed', $q$Actively developed with a focus on keeping server costs low for instance operators$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ecbe2f92-cfc5-4dba-ba88-7a0b655ae0ed', $q$Smaller user base and fewer communities than Reddit or even Lemmy$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ecbe2f92-cfc5-4dba-ba88-7a0b655ae0ed', $q$Federated model means content quality and moderation vary by instance$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ecbe2f92-cfc5-4dba-ba88-7a0b655ae0ed', $q$Newer project with a smaller contributor base than more established platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ecbe2f92-cfc5-4dba-ba88-7a0b655ae0ed', $q$Discovery of niche communities can be harder across a fragmented Fediverse$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ecbe2f92-cfc5-4dba-ba88-7a0b655ae0ed', $q$Self-hosting an instance requires server administration skills and ongoing maintenance$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ecbe2f92-cfc5-4dba-ba88-7a0b655ae0ed', $q$Is PieFed free to use?$q$, $q$Yes, PieFed is completely free and open source. Users can join a public instance for free or self-host their own instance.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ecbe2f92-cfc5-4dba-ba88-7a0b655ae0ed', $q$Who created PieFed?$q$, $q$PieFed was created by a developer known as Rimu Atkinson, who built it in Python with Flask as an alternative to Lemmy.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ecbe2f92-cfc5-4dba-ba88-7a0b655ae0ed', $q$How is PieFed different from Lemmy?$q$, $q$PieFed was built to address usability complaints about Lemmy, adding features like default comment collapsing for low-scoring replies, topic-organized communities, keyword filtering, and reputation indicators.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ecbe2f92-cfc5-4dba-ba88-7a0b655ae0ed', $q$Does PieFed work with Lemmy communities?$q$, $q$Yes, PieFed federates with Lemmy over ActivityPub, so PieFed users can browse and interact with Lemmy communities without Lemmy needing to run PieFed software.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ecbe2f92-cfc5-4dba-ba88-7a0b655ae0ed', $q$What is ActivityPub?$q$, $q$ActivityPub is the open federation protocol that lets independent servers, including PieFed, Lemmy, Mbin, and Mastodon, share posts and interactions across the Fediverse.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ecbe2f92-cfc5-4dba-ba88-7a0b655ae0ed', $q$Can I run my own PieFed instance?$q$, $q$Yes, PieFed's software is open source and can be self-hosted, letting individuals or communities run their own federated instance.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ecbe2f92-cfc5-4dba-ba88-7a0b655ae0ed', $q$Is PieFed owned by a company?$q$, $q$No, PieFed is a community-driven open-source project without a corporate owner, maintained primarily by its founding developer and volunteer contributors.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ecbe2f92-cfc5-4dba-ba88-7a0b655ae0ed', $q$What is the main PieFed instance called?$q$, $q$The primary reference instance is hosted at piefed.social, though other independently operated PieFed instances also exist.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ecbe2f92-cfc5-4dba-ba88-7a0b655ae0ed', $q$Reddit refugees seeking a federated alternative$q$, $q$Users who left Reddit over API pricing and policy changes join PieFed communities for a similar link-aggregation experience without centralized corporate control.$q$, $q$Former Reddit users seeking decentralized alternatives$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ecbe2f92-cfc5-4dba-ba88-7a0b655ae0ed', $q$Niche community hosting without platform risk$q$, $q$Community organizers run their own PieFed instance so their community is not subject to a single platform's sudden rule or monetization changes.$q$, $q$Community moderators and organizers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ecbe2f92-cfc5-4dba-ba88-7a0b655ae0ed', $q$Fediverse enthusiasts building interoperable communities$q$, $q$Fediverse users who already use Mastodon or Lemmy adopt PieFed to participate in federated discussions across multiple interoperable platforms.$q$, $q$Fediverse and decentralized social media enthusiasts$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ecbe2f92-cfc5-4dba-ba88-7a0b655ae0ed', $q$Self-Hosted / Public Instance$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full access to PieFed communities and discussions","Federation with Lemmy and Mbin via ActivityPub","Topic-organized communities","Keyword post filtering","Comment collapsing and reputation indicators","Option to self-host your own instance"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ecbe2f92-cfc5-4dba-ba88-7a0b655ae0ed', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$PieFed is a free, open-source, federated link-aggregation and discussion platform built on the ActivityPub protocol, offering a Reddit-like experience of communities, posts, votes, and comments without being owned or controlled by a single company. It was created by developer Rimu Atkinson as a Python and Flask-based alternative to Lemmy.$q$, $q$Because it federates over ActivityPub, PieFed instances interoperate directly with Lemmy and Mbin servers, letting users on any of these platforms subscribe to and interact with communities hosted elsewhere in the Fediverse without needing separate accounts.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ecbe2f92-cfc5-4dba-ba88-7a0b655ae0ed', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$PieFed organizes content into communities grouped by topic, supports upvoting and downvoting, and automatically collapses low-scoring comments to reduce the visibility of harassment or low-quality replies. It includes keyword-based post filtering so users can hide content they are not interested in, and it displays reputation indicators next to users with a history of low-quality contributions.$q$, $q$The platform federates with Lemmy and Mbin over ActivityPub, so communities and their discussions can be accessed across instances without requiring every server to run identical software, extending PieFed's reach into the broader Fediverse alongside Mastodon and similar platforms.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ecbe2f92-cfc5-4dba-ba88-7a0b655ae0ed', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$PieFed is completely free, open-source software with no subscription plans or paid tiers. Anyone can join an existing public instance such as piefed.social for free, or self-host their own instance at no software cost.$q$, $q$Running a self-hosted instance requires server infrastructure, which is the only real cost involved, consistent with how other Fediverse platforms like Mastodon and Lemmy are typically funded through donations to individual instance operators.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ecbe2f92-cfc5-4dba-ba88-7a0b655ae0ed', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ecbe2f92-cfc5-4dba-ba88-7a0b655ae0ed', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d3afb8a6-1eeb-4106-9923-58f01f27af75', $q$Text-to-video generation$q$, $q$Generates short video clips directly from written text prompts.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d3afb8a6-1eeb-4106-9923-58f01f27af75', $q$Image-to-video generation$q$, $q$Animates still images into short video clips, available even on the free plan.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d3afb8a6-1eeb-4106-9923-58f01f27af75', $q$Pikaffects$q$, $q$Signature branded visual effects that apply dramatic transformations like dissolving or exploding objects in a scene.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d3afb8a6-1eeb-4106-9923-58f01f27af75', $q$Pikaframes$q$, $q$Keyframe-based video generation tool for more controlled, structured video output.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d3afb8a6-1eeb-4106-9923-58f01f27af75', $q$Pikascenes$q$, $q$Combines multiple reference images into a single AI-generated scene.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d3afb8a6-1eeb-4106-9923-58f01f27af75', $q$Multiple resolution tiers$q$, $q$Supports output ranging from 480p on the free plan up to 1080p on paid plans.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d3afb8a6-1eeb-4106-9923-58f01f27af75', $q$Commercial usage rights$q$, $q$Paid plans include commercial use rights and watermark-free downloads for generated videos.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d3afb8a6-1eeb-4106-9923-58f01f27af75', $q$Free plan available to try core video generation features without payment$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d3afb8a6-1eeb-4106-9923-58f01f27af75', $q$Distinctive Pikaffects make it popular for social-media-ready, stylized content$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d3afb8a6-1eeb-4106-9923-58f01f27af75', $q$Multiple paid tiers scale credit allowances and speed to different usage levels$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d3afb8a6-1eeb-4106-9923-58f01f27af75', $q$Backed by well-known investors, suggesting continued product investment$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d3afb8a6-1eeb-4106-9923-58f01f27af75', $q$Fast generation speeds compared to some competing AI video tools$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d3afb8a6-1eeb-4106-9923-58f01f27af75', $q$Simple, self-serve credit-based pricing that is easy to understand$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d3afb8a6-1eeb-4106-9923-58f01f27af75', $q$Free plan output is limited to 480p resolution with watermarks and no commercial use$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d3afb8a6-1eeb-4106-9923-58f01f27af75', $q$Credit-based pricing can become expensive for high-volume commercial use$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d3afb8a6-1eeb-4106-9923-58f01f27af75', $q$Higher-resolution and faster generation are gated behind paid tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d3afb8a6-1eeb-4106-9923-58f01f27af75', $q$AI-generated video quality and consistency can vary depending on prompt complexity$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d3afb8a6-1eeb-4106-9923-58f01f27af75', $q$Faces intense competition from well-funded rivals like Runway, Sora, and Kling AI$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d3afb8a6-1eeb-4106-9923-58f01f27af75', $q$What is Pika?$q$, $q$Pika is an AI video and image generation platform, built by Pika Labs, that creates and edits short videos from text prompts, images, or existing footage.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d3afb8a6-1eeb-4106-9923-58f01f27af75', $q$Who founded Pika?$q$, $q$Pika was founded in April 2023 by Demi Guo and Chenlin Meng, both former Stanford AI PhD students.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d3afb8a6-1eeb-4106-9923-58f01f27af75', $q$Is Pika free to use?$q$, $q$Yes, Pika offers a free plan with 80 monthly video credits at 480p resolution, though output is watermarked and cannot be used commercially.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d3afb8a6-1eeb-4106-9923-58f01f27af75', $q$How much does Pika cost?$q$, $q$Paid plans, billed yearly, start at 8 dollars per month for the Standard tier, with Pro at 28 dollars per month and Fancy at 76 dollars per month, each offering more monthly credits and faster generation.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d3afb8a6-1eeb-4106-9923-58f01f27af75', $q$What are Pikaffects?$q$, $q$Pikaffects are Pika's signature branded video effects that apply dramatic transformations, such as dissolving or exploding objects, to a generated clip.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d3afb8a6-1eeb-4106-9923-58f01f27af75', $q$How much funding has Pika raised?$q$, $q$Pika has raised roughly 135 million dollars across a 55 million dollar Series A in 2023 and an 80 million dollar Series B in 2024, which valued the company at about 470 million dollars.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d3afb8a6-1eeb-4106-9923-58f01f27af75', $q$How does Pika compare to Runway or Sora?$q$, $q$Pika is generally seen as more focused on fast, stylized, and social-friendly short video effects, while Runway targets professional creators and OpenAI's Sora emphasizes high-fidelity photorealistic generation.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d3afb8a6-1eeb-4106-9923-58f01f27af75', $q$Is pika.art the same as other companies named Pika?$q$, $q$No. This profile refers specifically to Pika Labs, the AI video generation company at pika.art; other unrelated companies in different industries also use the name Pika.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d3afb8a6-1eeb-4106-9923-58f01f27af75', $q$Social media and short-form video content$q$, $q$Content creators use Pika to quickly generate eye-catching, stylized video clips for platforms like TikTok and Instagram.$q$, $q$Social media creators and influencers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d3afb8a6-1eeb-4106-9923-58f01f27af75', $q$Marketing and advertising asset creation$q$, $q$Marketing teams use Pika's commercial-tier plans to generate short promotional video assets without hiring a video production crew.$q$, $q$Marketers and small business owners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d3afb8a6-1eeb-4106-9923-58f01f27af75', $q$Rapid concept and storyboard visualization$q$, $q$Filmmakers and creative teams use Pika to quickly visualize concepts or storyboards before committing to full production.$q$, $q$Filmmakers and creative professionals$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d3afb8a6-1eeb-4106-9923-58f01f27af75', $q$Free$q$, $q$$0/month$q$, $q$Monthly$q$, NULL, $q$["80 monthly video credits","480p resolution only","Image-to-video generation","Basic editing tools","Watermarked downloads","No commercial use"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d3afb8a6-1eeb-4106-9923-58f01f27af75', $q$Standard$q$, $q$$8/month$q$, $q$Billed yearly$q$, NULL, $q$["700 monthly video credits","Full resolution access","Pikaframes and Pikascenes tools","Commercial use permitted","Watermark-free downloads","Fast generation speeds"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d3afb8a6-1eeb-4106-9923-58f01f27af75', $q$Pro$q$, $q$$28/month$q$, $q$Billed yearly$q$, NULL, $q$["2,300 monthly video credits","Full feature access","Faster generation speeds","Commercial use permitted","Watermark-free downloads"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d3afb8a6-1eeb-4106-9923-58f01f27af75', $q$Fancy$q$, $q$$76/month$q$, $q$Billed yearly$q$, NULL, $q$["6,000 monthly video credits","Full resolution and feature access","Fastest generation speeds","Priority access to new Pikaffects","Commercial use permitted","Watermark-free downloads"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d3afb8a6-1eeb-4106-9923-58f01f27af75', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Pika is an AI video and image generation platform founded in April 2023 by former Stanford AI PhD students Demi Guo and Chenlin Meng. The company set out to make AI-powered video creation and editing accessible to everyday creators, without requiring cameras, editing software expertise, or a production budget.$q$, $q$The platform, available at pika.art, lets users generate short videos from text prompts, transform still images into video, and apply distinctive visual effects to existing footage, positioning itself as a fast, playful tool for social and marketing content rather than a full professional filmmaking suite.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d3afb8a6-1eeb-4106-9923-58f01f27af75', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Pika supports text-to-video and image-to-video generation, along with signature effects branded as Pikaffects that apply dramatic, often humorous transformations like dissolving or exploding objects within a generated clip. Additional tools include Pikaframes for keyframe-driven video generation and Pikascenes for combining several reference images into one generated scene.$q$, $q$The platform offers multiple resolution and speed tiers depending on subscription level, ranging from 480p on the free plan up to full high-definition output on paid plans, along with commercial usage rights and watermark-free downloads for paying subscribers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d3afb8a6-1eeb-4106-9923-58f01f27af75', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Pika uses a freemium, credit-based pricing model. The free plan includes 80 monthly video credits, 480p-only resolution, basic editing tools, and watermarked output with no commercial use rights.$q$, $q$Paid plans, billed yearly, start with the Standard tier at 8 dollars per month for 700 monthly credits and full-resolution, commercial-use, watermark-free video, scaling up through the Pro tier at 28 dollars per month for 2,300 credits, and the Fancy tier at 76 dollars per month for 6,000 credits with the fastest generation speeds and priority access to new Pikaffects.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d3afb8a6-1eeb-4106-9923-58f01f27af75', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
